580	func (s *Store) Claim(id, assignee string) error {
581		return s.ClaimWithOptions(id, assignee, "", "")
582	}
583	
584	// ClaimWithOptions sets a bead to in_progress with extended claim metadata.
585	// session and worktree are optional; machine is derived from os.Hostname().
586	// A stalled in_progress bead (external lease older than HeartbeatTTL) is
587	// reclaimed atomically under the store's lock.
588	func (s *Store) ClaimWithOptions(id, assignee, session, worktree string) error {
589		machine, _ := os.Hostname()
590		if envID := os.Getenv("DDX_MACHINE_ID"); envID != "" {
591			machine = envID
592		}
593		return s.WithLock(func() error {
594			beads, _, err := s.readAllLatestRaw()
595			if err != nil {
596				return err
597			}
598			for i := range beads {
599				if beads[i].ID != id {
600					continue
601				}
602				switch beads[i].Status {
603				case StatusOpen:
604					// normal claim path
605				case StatusInProgress:
606					if !claimLeaseIsStale(s, beads[i].Extra, id) {
607						return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
608					}
609					// stalled claim — reclaim atomically below
610				default:
611					return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
612				}
613				// Refuse claims on beads parked with last_status=push_failed:
614				// the previous attempt landed locally but `git push` was rejected,
615				// so the local commit history exists only on this machine. Re-running
616				// primary work would duplicate or strand commits. The operator must
617				// clear execute-loop-last-status (e.g. by manually pushing or
618				// resetting) before another attempt is allowed.
619				if last, ok := beads[i].Extra["execute-loop-last-status"].(string); ok && last == "push_failed" {
620					detail, _ := beads[i].Extra["execute-loop-last-detail"].(string)
621					if detail != "" {
622						return fmt.Errorf("bead: refusing to claim %s — previous attempt landed locally but push failed (%s); clear execute-loop-last-status to retry", id, detail)
623					}
624					return fmt.Errorf("bead: refusing to claim %s — previous attempt landed locally but push failed; clear execute-loop-last-status to retry", id)
625				}
626				if beads[i].Extra == nil {
627					beads[i].Extra = make(map[string]any)
628				}
629				now := time.Now().UTC()
630				beads[i].Status = StatusInProgress
631				beads[i].Owner = assignee
632				beads[i].UpdatedAt = now
633				beads[i].Extra["claimed-at"] = now.Format(time.RFC3339)
634				beads[i].Extra["claimed-pid"] = fmt.Sprintf("%d", os.Getpid())
635				beads[i].Extra["execute-loop-heartbeat-at"] = now.Format(time.RFC3339Nano)
636				if machine != "" {
637					beads[i].Extra["claimed-machine"] = machine
638				}
639				if session != "" {
640					beads[i].Extra["claimed-session"] = session
641				}
642				if worktree != "" {
643					beads[i].Extra["claimed-worktree"] = worktree
644				}
645				if err := s.validateBead(&beads[i]); err != nil {
646					return err
647				}
648				if err := s.runHook("validate-bead-update", &beads[i]); err != nil {
649					return err
650				}
651				if err := s.WriteAll(beads); err != nil {
652					return err
653				}
654				return s.TouchClaimHeartbeat(id)
655			}
656			return fmt.Errorf("bead: not found: %s", id)
657		})
658	}
